// Validate return_url to prevent open redirect vulnerabilities
function isValidReturnUrl(url) {
  if (!url || typeof url !== 'string') return false;

  // Only allow relative paths or URLs on the same domain
  const ALLOWED_HOSTS = [
    'localhost',
    'localhost:3000',
    'yourdomain.com',
    'www.yourdomain.com',
  ];

  // Allow relative URLs
  if (url.startsWith('/') && !url.startsWith('//')) {
    return true;
  }

  // Check absolute URLs against allowed hosts
  try {
    const parsed = new URL(url);
    return ALLOWED_HOSTS.includes(parsed.host) &&
           (parsed.protocol === 'https:' || parsed.protocol === 'http:');
  } catch {
    return false;
  }
}

